defmodule AdminDashboard.Router do
  use Phoenix.Router
  import Phoenix.Controller

  pipeline :api do
    plug :accepts, ["json"]
  end

  scope "/api/admin", AdminDashboard do
    pipe_through :api

    get "/users", AdminController, :index
    get "/users/search", AdminController, :search
    get "/users/sorted", AdminController, :list_sorted
    get "/users/paginated", AdminController, :list_paginated
    get "/users/advanced", AdminController, :advanced_search
    get "/users/count", AdminController, :count_by_role
  end
end

